						"feral bloodswarmer", -- [6]
						"earthrager", -- [7]
						"crawler mine", -- [8]
						"rezan", -- [9]
					},
					["PlaterCore"] = 1,
					["__TrashAt"] = 1605750230,
					["NpcNames"] = {
						"smuggled crawg", -- [1]
